module top_module( E, SE, CK, ECK );input E, SE, CK;
  output ECK;

  reg ECK;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CK or posedge dbg_halt) begin
    if (SE) begin
      ECK <= 1'b1;
    end else if (E) begin
      ECK <= 1'b0;
    end
  end
endmodule
